parameters.jsCode:
const item = $input.first();
const aiRaw = item.json;

let aiData = {};
try {
  const content = aiRaw.choices?.[0]?.message?.content || '{}';
  aiData = JSON.parse(content);
} catch (e) {
  // Fallback if AI response is malformed
  aiData = {
    contact_name: 'Unknown',
    contact_company: 'Unknown',
    relationship_type: 'Other',
    interaction_type: 'Other',
    interaction_summary: 'AI parse error — review manually',
    sentiment: 'Neutral',
    follow_up_required: 'No',
    follow_up_action: 'None',
    follow_up_days: 0,
    urgency: 'Low',
    deal_stage: 'None',
    estimated_value: 0,
    key_topics: '',
    language: 'English',
    relationship_strength: 'New'
  };
}

// Retrieve context from Set node
const ctx = $('⚙️ Set — Normalize Fields').first().json;

const record = {
  timestamp: new Date().toISOString(),
  message_id: ctx.message_id || '',
  thread_id: ctx.thread_id || '',
  to_address: ctx.to_address || '',
  to_name: ctx.to_name || '',
  subject: ctx.subject || '',
  sent_date: ctx.sent_date || '',
  // AI-enriched fields
  contact_name: aiData.contact_name || ctx.to_name || 'Unknown',
  contact_company: aiData.contact_company || 'Unknown',
  relationship_type: aiData.relationship_type || 'Other',
  interaction_type: aiData.interaction_type || 'Other',
  interaction_summary: aiData.interaction_summary || '',
  sentiment: aiData.sentiment || 'Neutral',
  follow_up_required: aiData.follow_up_required || 'No',
  follow_up_action: aiData.follow_up_action || 'None',
  follow_up_days: parseInt(aiData.follow_up_days) || 0,
  urgency: aiData.urgency || 'Low',
  deal_stage: aiData.deal_stage || 'None',
  estimated_value: parseFloat(aiData.estimated_value) || 0,
  key_topics: aiData.key_topics || '',
  language: aiData.language || 'English',
  relationship_strength: aiData.relationship_strength || 'New',
  // Pass config forward
  openai_key: ctx.openai_key,
  sheet_id: ctx.sheet_id,
  slack_enabled: ctx.slack_enabled,
  slack_channel: ctx.slack_channel
};

return [{ json: record }];

